    69→template <class FactoryCb>
    70→class DynamicFilterConfigProviderImpl : public DynamicFilterConfigProviderImplBase,
    71→                                        public DynamicFilterConfigProvider<FactoryCb> {
    72→public:
    73→  DynamicFilterConfigProviderImpl(
    74→      FilterConfigSubscriptionSharedPtr& subscription,
    75→      const absl::flat_hash_set<std::string>& require_type_urls, ThreadLocal::SlotAllocator& tls,
    76→      ProtobufTypes::MessagePtr&& default_config, bool last_filter_in_filter_chain,
    77→      const std::string& filter_chain_type, absl::string_view stat_prefix,
    78→      const Network::ListenerFilterMatcherSharedPtr& listener_filter_matcher)
    79→      : DynamicFilterConfigProviderImplBase(subscription, require_type_urls,
    80→                                            last_filter_in_filter_chain, filter_chain_type),
    81→        listener_filter_matcher_(listener_filter_matcher), stat_prefix_(stat_prefix),
    82→        main_config_(std::make_shared<MainConfig>(tls)),
    83→        default_configuration_(std::move(default_config)){};
    84→
    85→  ~DynamicFilterConfigProviderImpl() override {
    86→    auto& tls = main_config_->tls_;
    87→    if (!tls->isShutdown()) {
    88→      tls->runOnAllThreads([](OptRef<ThreadLocalConfig> tls) { tls->config_ = {}; },
    89→                           // Extend the lifetime of TLS by capturing main_config_, because
    90→                           // otherwise, the callback to clear TLS worker content is not executed.
    91→                           [main_config = main_config_]() {
    92→                             // Explicitly delete TLS on the main thread.
    93→                             main_config->tls_.reset();
    94→                             // Explicitly clear the last config instance here in case it has its
    95→                             // own TLS.
    96→                             main_config->current_config_ = {};
    97→                           });
    98→    }
    99→  }
   100→
   101→  // Config::ExtensionConfigProvider
   102→  const std::string& name() override { return DynamicFilterConfigProviderImplBase::name(); }
   103→  OptRef<FactoryCb> config() override {
   104→    if (auto& optional_config = (*main_config_->tls_)->config_; optional_config.has_value()) {
   105→      return optional_config.value();
   106→    }
   107→    return {};
   108→  }
   109→
   110→  // Config::DynamicExtensionConfigProviderBase
   111→  absl::Status onConfigUpdate(const Protobuf::Message& message, const std::string&,
   112→                              Config::ConfigAppliedCb applied_on_all_threads) override {
   113→    const absl::StatusOr<FactoryCb> config_or_error = instantiateFilterFactory(message);
   114→    RETURN_IF_STATUS_NOT_OK(config_or_error);
   115→    update(config_or_error.value(), applied_on_all_threads);
   116→    return absl::OkStatus();
   117→  }
   118→
   119→  absl::Status onConfigRemoved(Config::ConfigAppliedCb applied_on_all_threads) override {
   120→    absl::optional<FactoryCb> cb;
   121→    if (default_configuration_) {
   122→      auto cb_or_error = instantiateFilterFactory(*default_configuration_);
   123→      RETURN_IF_STATUS_NOT_OK(cb_or_error);
   124→      cb = cb_or_error.value();
   125→    }
   126→    update(cb, applied_on_all_threads);
   127→    return absl::OkStatus();
   128→  }
   129→
   130→  absl::Status applyDefaultConfiguration() override {
   131→    if (default_configuration_) {
   132→      return onConfigUpdate(*default_configuration_, "", nullptr);
   133→    }
   134→    return absl::OkStatus();
   135→  }
   136→  const Network::ListenerFilterMatcherSharedPtr& getListenerFilterMatcher() override {
   137→    return listener_filter_matcher_;
   138→  }
   139→
   140→protected:
   141→  const std::string& getStatPrefix() const { return stat_prefix_; }
   142→  const Network::ListenerFilterMatcherSharedPtr listener_filter_matcher_;
   143→
   144→private:
   145→  virtual absl::StatusOr<FactoryCb>
   146→  instantiateFilterFactory(const Protobuf::Message& message) const PURE;
   147→
   148→  void update(absl::optional<FactoryCb> config, Config::ConfigAppliedCb applied_on_all_threads) {
   149→    // This call must not capture 'this' as it is invoked on all workers asynchronously.
   150→    main_config_->tls_->runOnAllThreads(
   151→        [config](OptRef<ThreadLocalConfig> tls) { tls->config_ = config; },
   152→        [main_config = main_config_, config, applied_on_all_threads]() {
   153→          // This happens after all workers have discarded the previous config so
   154→          // it can be safely deleted on the main thread by an update with the new
   155→          // config.
   156→          main_config->current_config_ = config;
   157→          if (applied_on_all_threads) {
   158→            applied_on_all_threads();
   159→          }
   160→        });
   161→  }
   162→
   163→  struct ThreadLocalConfig : public ThreadLocal::ThreadLocalObject {
   164→    ThreadLocalConfig() : config_{absl::nullopt} {}
   165→    absl::optional<FactoryCb> config_{};
   166→  };
   167→
   168→  // Currently applied configuration to ensure that the main thread deletes the last reference to
   169→  // it. Filter factories may hold their own thread local storage which is required to be deleted
   170→  // on the main thread.
   171→  struct MainConfig {
   172→    MainConfig(ThreadLocal::SlotAllocator& tls)
   173→        : tls_(std::make_unique<ThreadLocal::TypedSlot<ThreadLocalConfig>>(tls)) {
   174→      tls_->set([](Event::Dispatcher&) { return std::make_shared<ThreadLocalConfig>(); });
   175→    }
   176→    absl::optional<FactoryCb> current_config_{absl::nullopt};
   177→    ThreadLocal::TypedSlotPtr<ThreadLocalConfig> tls_;
   178→  };
   179→  const std::string stat_prefix_;
   180→  std::shared_ptr<MainConfig> main_config_;
   181→  const ProtobufTypes::MessagePtr default_configuration_;
   182→};
   183→
   184→// Struct of canonical filter name and HTTP stream filter factory callback.
   185→struct NamedHttpFilterFactoryCb {
   186→  // Canonical filter name.
   187→  std::string name;
   188→  // Factory function used to create filter instances.
   189→  Http::FilterFactoryCb factory_cb;
   190→};
   191→
   192→// Implementation of a HTTP dynamic filter config provider.
   193→// NeutralHttpFilterConfigFactory can either be a NamedHttpFilterConfigFactory
   194→// or an UpstreamHttpFilterConfigFactory.
   195→template <class FactoryCtx, class NeutralHttpFilterConfigFactory>
   196→class HttpDynamicFilterConfigProviderImpl
   197→    : public DynamicFilterConfigProviderImpl<NamedHttpFilterFactoryCb> {
   198→public:
   199→  HttpDynamicFilterConfigProviderImpl(
   200→      FilterConfigSubscriptionSharedPtr& subscription,
   201→      const absl::flat_hash_set<std::string>& require_type_urls,
   202→      Server::Configuration::ServerFactoryContext& server_context, FactoryCtx& factory_context,
   203→      ProtobufTypes::MessagePtr&& default_config, bool last_filter_in_filter_chain,
   204→      const std::string& filter_chain_type, absl::string_view stat_prefix,
   205→      const Network::ListenerFilterMatcherSharedPtr& listener_filter_matcher)
   206→      : DynamicFilterConfigProviderImpl(subscription, require_type_urls,
   207→                                        server_context.threadLocal(), std::move(default_config),
   208→                                        last_filter_in_filter_chain, filter_chain_type, stat_prefix,
   209→                                        listener_filter_matcher),
   210→        server_context_(server_context), factory_context_(factory_context) {}
   211→  void validateMessage(const std::string& config_name, const Protobuf::Message& message,
   212→                       const std::string& factory_name) const override {
   213→    auto* factory =
   214→        Registry::FactoryRegistry<NeutralHttpFilterConfigFactory>::getFactory(factory_name);
   215→    const bool is_terminal_filter = factory->isTerminalFilterByProto(message, server_context_);
   216→    Config::Utility::validateTerminalFilters(config_name, factory_name, filter_chain_type_,
   217→                                             is_terminal_filter, last_filter_in_filter_chain_);
   218→  }
   219→
   220→private:
   221→  absl::StatusOr<NamedHttpFilterFactoryCb>
   222→  instantiateFilterFactory(const Protobuf::Message& message) const override {
   223→    auto* factory = Registry::FactoryRegistry<NeutralHttpFilterConfigFactory>::getFactoryByType(
   224→        message.GetTypeName());
   225→    absl::StatusOr<Http::FilterFactoryCb> error_or_factory =
   226→        factory->createFilterFactoryFromProto(message, getStatPrefix(), factory_context_);
   227→    RETURN_IF_STATUS_NOT_OK(error_or_factory);
   228→    return NamedHttpFilterFactoryCb{factory->name(), error_or_factory.value()};
   229→  }
   230→
   231→  Server::Configuration::ServerFactoryContext& server_context_;
   232→  FactoryCtx& factory_context_;
   233→};
   234→
   235→template <class FactoryCtx, class NeutralNetworkFilterConfigFactory>
   236→class NetworkDynamicFilterConfigProviderImplBase
   237→    : public DynamicFilterConfigProviderImpl<Network::FilterFactoryCb> {
   238→public:
   239→  NetworkDynamicFilterConfigProviderImplBase(
   240→      FilterConfigSubscriptionSharedPtr& subscription,
   241→      const absl::flat_hash_set<std::string>& require_type_urls,
   242→      Server::Configuration::ServerFactoryContext& server_context, FactoryCtx& factory_context,
   243→      ProtobufTypes::MessagePtr&& default_config, bool last_filter_in_filter_chain,
   244→      const std::string& filter_chain_type, absl::string_view stat_prefix,
   245→      const Network::ListenerFilterMatcherSharedPtr& listener_filter_matcher)
   246→      : DynamicFilterConfigProviderImpl(subscription, require_type_urls,
   247→                                        server_context.threadLocal(), std::move(default_config),
   248→                                        last_filter_in_filter_chain, filter_chain_type, stat_prefix,
   249→                                        listener_filter_matcher),
   250→        server_context_(server_context), factory_context_(factory_context) {}
   251→
   252→private:
   253→  absl::StatusOr<Network::FilterFactoryCb>
   254→  instantiateFilterFactory(const Protobuf::Message& message) const override {
   255→    auto* factory = Registry::FactoryRegistry<NeutralNetworkFilterConfigFactory>::getFactoryByType(
   256→        message.GetTypeName());
   257→    absl::StatusOr<Network::FilterFactoryCb> cb_or_error =
   258→        factory->createFilterFactoryFromProto(message, factory_context_);
   259→    RETURN_IF_STATUS_NOT_OK(cb_or_error);
   260→    return cb_or_error.value();
   261→  }
   262→
   263→protected:
   264→  Server::Configuration::ServerFactoryContext& server_context_;
   265→  FactoryCtx& factory_context_;
   266→};
   267→
   268→template <class FactoryCtx, class NeutralNetworkFilterConfigFactory>
   269→class DownstreamNetworkDynamicFilterConfigProviderImpl
   270→    : public NetworkDynamicFilterConfigProviderImplBase<FactoryCtx,
   271→                                                        NeutralNetworkFilterConfigFactory> {
   272→public:
   273→  using NetworkDynamicFilterConfigProviderImplBase<
   274→      FactoryCtx, NeutralNetworkFilterConfigFactory>::NetworkDynamicFilterConfigProviderImplBase;
   275→
   276→  void validateMessage(const std::string& config_name, const Protobuf::Message& message,
   277→                       const std::string& factory_name) const override {
   278→    auto* factory =
   279→        Registry::FactoryRegistry<NeutralNetworkFilterConfigFactory>::getFactory(factory_name);
   280→    const bool is_terminal_filter =
   281→        factory->isTerminalFilterByProto(message, this->server_context_);
   282→    Config::Utility::validateTerminalFilters(config_name, factory_name, this->filter_chain_type_,
   283→                                             is_terminal_filter,
   284→                                             this->last_filter_in_filter_chain_);
   285→  }
   286→};
   287→
   288→template <class FactoryCtx, class NeutralNetworkFilterConfigFactory>
   289→class UpstreamNetworkDynamicFilterConfigProviderImpl
   290→    : public NetworkDynamicFilterConfigProviderImplBase<FactoryCtx,
   291→                                                        NeutralNetworkFilterConfigFactory> {
   292→public:
   293→  using NetworkDynamicFilterConfigProviderImplBase<
   294→      FactoryCtx, NeutralNetworkFilterConfigFactory>::NetworkDynamicFilterConfigProviderImplBase;
